307→// --------------------------------------------------------------------------------------------------------------------
308→//	Create list of segments boss is allowed to teleport to at segptr.
309→//	Set *num_segs.
310→//	Boss is allowed to teleport to segments he fits in (calls object_intersects_wall) and
311→//	he can reach from his initial position (calls find_connected_distance).
312→//	If size_check is set, then only add segment if boss can fit in it, else any segment is legal.
313→//	one_wall_hack added by MK, 10/13/95: A mega-hack!  Set to !0 to ignore the 
314→void init_boss_segments(short segptr[], int *num_segs, int size_check, int one_wall_hack)
315→{
316→	int			boss_objnum=-1;
317→	int			i;
318→
319→	*num_segs = 0;
320→#ifdef EDITOR
321→	N_selected_segs = 0;
322→#endif
323→
324→
325→if (size_check)
326→	mprintf((0, "Boss fits in segments:\n"));
327→	//	See if there is a boss.  If not, quick out.
328→	for (i=0; i<=Highest_object_index; i++)
329→		if ((Objects[i].type == OBJ_ROBOT) && (Robot_info[Objects[i].id].boss_flag)) {
330→			if (boss_objnum != -1)		//	There are two bosses in this mine!  i and boss_objnum!
331→				Int3();			//do int3 here instead of assert so museum will work
332→			boss_objnum = i;
333→		}
334→
335→	if (boss_objnum != -1) {
336→		int			original_boss_seg;
337→		vms_vector	original_boss_pos;
338→		object		*boss_objp = &Objects[boss_objnum];
339→		int			head, tail;
340→		int			seg_queue[QUEUE_SIZE];
341→//ALREADY IN RENDER.H		int8_t			visited[MAX_SEGMENTS];
342→		fix			boss_size_save;
343→
344→		boss_size_save = boss_objp->size;
345→		// -- Causes problems!!	-- boss_objp->size = fixmul((F1_0/4)*3, boss_objp->size);
346→		original_boss_seg = boss_objp->segnum;
347→		original_boss_pos = boss_objp->pos;
348→		head = 0;
349→		tail = 0;
350→		seg_queue[head++] = original_boss_seg;
351→
352→		segptr[(*num_segs)++] = original_boss_seg;
353→		mprintf((0, "%4i ", original_boss_seg));
354→		#ifdef EDITOR
355→		Selected_segs[N_selected_segs++] = original_boss_seg;
356→		#endif
357→
358→		for (i=0; i<=Highest_segment_index; i++)
359→			visited[i] = 0;
360→
361→		while (tail != head) {
362→			int		sidenum;
363→			segment	*segp = &Segments[seg_queue[tail++]];
364→
365→			tail &= QUEUE_SIZE-1;
366→
367→			for (sidenum=0; sidenum<MAX_SIDES_PER_SEGMENT; sidenum++) {
368→				int	w;
369→
370→				if (((w = WALL_IS_DOORWAY(segp, sidenum)) & WID_FLY_FLAG) || one_wall_hack) {
371→					//	If we get here and w == WID_WALL, then we want to process through this wall, else not.
372→					if (IS_CHILD(segp->children[sidenum])) {
373→						if (one_wall_hack)
374→							one_wall_hack--;
375→					} else
376→						continue;
377→
378→					if (visited[segp->children[sidenum]] == 0) {
379→						seg_queue[head++] = segp->children[sidenum];
380→						visited[segp->children[sidenum]] = 1;
381→						head &= QUEUE_SIZE-1;
382→						if (head > tail) {
383→							if (head == tail + QUEUE_SIZE-1)
384→								Int3();	//	queue overflow.  Make it bigger!
385→						} else
386→							if (head+QUEUE_SIZE == tail + QUEUE_SIZE-1)
387→								Int3();	//	queue overflow.  Make it bigger!
388→	
389→						if ((!size_check) || boss_fits_in_seg(boss_objp, segp->children[sidenum])) {
390→							segptr[(*num_segs)++] = segp->children[sidenum];
391→							if (size_check) mprintf((0, "%4i ", segp->children[sidenum]));
392→							#ifdef EDITOR
393→							Selected_segs[N_selected_segs++] = segp->children[sidenum];
394→							#endif
395→							if (*num_segs >= MAX_BOSS_TELEPORT_SEGS) {
396→								mprintf((1, "Warning: Too many boss teleport segments.  Found %i after searching %i/%i segments.\n", MAX_BOSS_TELEPORT_SEGS, segp->children[sidenum], Highest_segment_index+1));
397→								tail = head;
398→							}
399→						}
400→					}
401→				}
402→			}
403→
404→		}
405→
406→		boss_objp->size = boss_size_save;
407→		boss_objp->pos = original_boss_pos;
408→		obj_relink(boss_objnum, original_boss_seg);
409→
410→	}
411→
412→}
