	else
		john_cheats_index_3 = 0;
}

//	----------------------------------------------------------------
//	Do *dest = *delta unless:
//				*delta is pretty small
//		and	they are of different signs.
void set_rotvel_and_saturate(fix* dest, fix delta)
{
	if ((delta ^ *dest) < 0) {
		if (abs(delta) < F1_0 / 8) {
			// mprintf((0, "D"));
			*dest = delta / 4;
		}
		else
			// mprintf((0, "d"));
			*dest = delta;
	}
	else {
		// mprintf((0, "!"));
		*dest = delta;
	}
}

